import time
import random
import requests


class APIError(Exception):
    def __init__(self, status_code: int, message: str, body: dict = None):
        self.status_code = status_code
        self.message = message
        self.body = body or {}
        super().__init__(f"HTTP {status_code}: {message}")


class ClientError(APIError):
    """4xx errors — do not retry."""


class ServerError(APIError):
    """5xx errors — safe to retry if idempotent."""


def classify_response(resp: requests.Response) -> None:
    """Raise the appropriate error type if the response is not 2xx."""
    if resp.ok:
        return
    try:
        body = resp.json()
    except Exception:
        body = {}
    if 400 <= resp.status_code < 500:
        raise ClientError(resp.status_code, resp.reason, body)
    raise ServerError(resp.status_code, resp.reason, body)


def call_with_retry(
    url: str,
    *,
    max_attempts: int = 4,
    base_delay: float = 1.0,
    max_delay: float = 30.0,
    headers: dict = None,
) -> dict:
    """GET a JSON endpoint, retrying on 5xx with exponential backoff + full jitter."""
    for attempt in range(max_attempts):
        resp = requests.get(url, headers=headers or {}, timeout=10)
        try:
            classify_response(resp)
            return resp.json()
        except ClientError:
            raise  # never retry 4xx
        except ServerError as exc:
            if attempt + 1 >= max_attempts:
                raise
            cap = min(base_delay * (2 ** attempt), max_delay)
            delay = random.uniform(0, cap)  # full jitter
            print(f"[attempt {attempt+1}] {exc} — retrying in {delay:.2f}s")
            time.sleep(delay)
    raise RuntimeError('unreachable')


# Example
if __name__ == "__main__":
    try:
        data = call_with_retry("https://api.example.com/items/42")
        print(data)
    except ClientError as e:
        print(f"Bad request: {e.body.get('error', {}).get('message')}")
    except ServerError as e:
        print(f"Server unavailable after retries: {e}")

from dataclasses import dataclass, field
from typing import Optional, List


@dataclass
class FieldError:
    field: str
    code: str
    message: str


@dataclass
class StructuredAPIError:
    status: int
    code: str
    message: str
    fields: List[FieldError] = field(default_factory=list)
    request_id: Optional[str] = None

    def is_validation_error(self) -> bool:
        return self.status == 422 or self.code in {"VALIDATION_ERROR", "INVALID_INPUT"}

    def field_messages(self) -> dict:
        return {f.field: f.message for f in self.fields}


def parse_error_response(status: int, body: dict) -> StructuredAPIError:
    """Parse a JSON error body into a typed StructuredAPIError object."""
    err = body.get("error", {})
    raw_fields = err.get("details", [])
    fields = [
        FieldError(
            field=d.get("field", ""),
            code=d.get("code", ""),
            message=d.get("message", ""),
        )
        for d in raw_fields
        if d.get("field")
    ]
    return StructuredAPIError(
        status=status,
        code=err.get("code", "UNKNOWN"),
        message=err.get("message", "An error occurred."),
        fields=fields,
        request_id=body.get("request_id"),
    )


# Typical 422 body from a real API
body_422 = {
    "error": {
        "code": "VALIDATION_ERROR",
        "message": "One or more fields failed validation.",
        "details": [
            {"field": "email", "code": "INVALID_FORMAT", "message": "Must be a valid email address."},
            {"field": "age", "code": "OUT_OF_RANGE", "message": "Must be between 18 and 120."},
        ],
    },
    "request_id": "req_xyz789",
}

err = parse_error_response(422, body_422)
print(err.is_validation_error())    # True
print(err.field_messages())         # {'email': '...', 'age': '...'}
print(err.request_id)               # req_xyz789
